/** UsptReprtHistDao.insert */
insert into uspt_reprt_hist
	(
		hist_id
		, reprt_id
		, opetr_id
		, reprt_sttus_cd
		, process_cn
		, creator_id
		, created_dt
	) values (
		#{histId}
		, #{reprtId}
		, #{opetrId}
		, #{reprtSttusCd}
		, #{processCn}
		, #{creatorId}
		, #{createdDt}
	)
